// ----------------------------------------------------------------------------- // C3: Physical sensing components
instance MotorEncoder : DTDFVocab:SensingComponent [
    base:desc "Motor‑mounted position encoder providing motor shaft angle"
    DTDFVocab:producedData MotorEncoderAngleTransmitted
]

instance GearboxEncoder : DTDFVocab:SensingComponent [
    base:desc "Secondary position encoder located after the cycloidal gearbox providing output shaft angle"
    DTDFVocab:producedData GearboxEncoderAngleTransmitted
]

instance MotorCurrentSensor : DTDFVocab:SensingComponent [
    base:desc "Current sensor measuring motor phase current I_M"
    DTDFVocab:producedData MotorCurrentTransmitted
]

// -----------------------------------------------------------------------------
// C4: Physical-to-virtual interaction (DataTransmitted)
// -----------------------------------------------------------------------------
instance MotorEncoderAngleTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoder
]

instance GearboxEncoderAngleTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom GearboxEncoder
]

instance MotorCurrentTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorCurrentSensor
]

instance DerivedPhysicalDataTransmitted : DTDFVocab:DataTransmitted [
    DTDFVocab:producedFrom MotorEncoder, GearboxEncoder, MotorCurrentSensor
]

// -----------------------------------------------------------------------------
// C10: Data (raw and derived)
// -----------------------------------------------------------------------------
instance MotorEncoderAngleData : DTDFVocab:Data [
    base:desc "Array of motor encoder angles streamed via MQTT"
    DTDFVocab:fromData MotorEncoderAngleTransmitted
    DTDFVocab:inputTo MatlabSimulinkProcessingEnabler
]

instance GearboxEncoderAngleData : DTDFVocab:Data [
    base:desc "Array of gearbox output angles streamed via MQTT"
    DTDFVocab:fromData GearboxEncoderAngleTransmitted
    DTDFVocab:inputTo MatlabSimulinkProcessingEnabler
]

instance MotorCurrentData : DTDFVocab:Data [
    base:desc "Array of motor phase current I_M streamed via MQTT"
    DTDFVocab:fromData MotorCurrentTransmitted
    DTDFVocab:inputTo MatlabSimulinkProcessingEnabler
]

instance TorqueData : DTDFVocab:Data [
    base:desc "Derived torque τ calculated from current and motor parameters"
    DTDFVocab:fromData DerivedPhysicalDataTransmitted
    DTDFVocab:inputTo FrictionSimulationEnabler
]

instance AngularVelocityData : DTDFVocab:Data [
    base:desc "Derived angular velocity ω computed from encoder positions"
    DTDFVocab:fromData DerivedPhysicalDataTransmitted
    DTDFVocab:inputTo FrictionSimulationEnabler
]

instance AccelerationData : DTDFVocab:Data [
    base:desc "Derived angular acceleration computed from angular velocity"
    DTDFVocab:fromData DerivedPhysicalDataTransmitted
    DTDFVocab:inputTo FrictionSimulationEnabler
]

// -----------------------------------------------------------------------------
// C11: Enablers (tools & platforms)
// -----------------------------------------------------------------------------
instance MQTTPeerBroker : DTDFVocab:Enabler [
    base:desc "MQTT broker used to stream live sensor data to the digital shadow"
    DTDFVocab:enables DataIngestionService
]

instance MatlabSimulinkProcessingEnabler : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink environment that processes raw sensor traces"
    DTDFVocab:enables FrictionIdentificationService, DataVisualizationService
]

instance FrictionSimulationEnabler : DTDFVocab:Enabler [
    base:desc "MATLAB/Simulink engine executing friction models (Coulomb‑Viscous, Stribeck, Dahl, LuGre)"
    DTDFVocab:enables FrictionIdentificationService, FrictionParameterUpdateService
]

instance AssetAdministrationShellEnabler : DTDFVocab:Enabler [
    base:desc "Asset Administration Shell providing standardized representation of robot components"
    DTDFVocab:enables DataTraceabilityService
]

instance DashboardVisualizationEnabler : DTDFVocab:Enabler [
    base:desc "Dashboard platform visualising data traces and insights"
    DTDFVocab:enables DataVisualizationService
]

// -----------------------------------------------------------------------------
// C6: Services (functionalities offered by the digital shadow)
// -----------------------------------------------------------------------------
instance DataIngestionService : DTDFVocab:Service [
    base:desc "Ingestion of MQTT sensor streams into the digital twin"
    DTDFVocab:provides DataIngestionInsight
]

instance FrictionIdentificationService : DTDFVocab:Service [
    base:desc "Real‑time friction identification by comparing simulated and measured torque, velocity, and acceleration"
    DTDFVocab:provides UpdatedFrictionParametersInsight, FrictionIdentificationAction
]

instance DataVisualizationService : DTDFVocab:Service [
    base:desc "Visualization of live and historical data traces on an operator dashboard"
    DTDFVocab:provides DataVisualizationInsight
]

instance DataTraceabilityService : DTDFVocab:Service [
    base:desc "Traceability of data origins linking each data point to its originating sensor"
    DTDFVocab:provides DataTraceabilityInsight
]

instance FrictionParameterUpdateService : DTDFVocab:Service [
    base:desc "Generation and deployment of updated friction model parameters to the robot controller"
    DTDFVocab:provides FrictionParameterUpdateAction
]

// -----------------------------------------------------------------------------
// C17: Insights / Actions
// -----------------------------------------------------------------------------
instance UpdatedFrictionParametersInsight : DTDFVocab:Insight [
    base:desc "Insight that friction parameters have been identified and are ready for deployment"
]

instance FrictionIdentificationAction : DTDFVocab:Action [
    base:desc "Automatic execution of the friction model identification algorithm"
    DTDFVocab:IsAutomatic true
]

instance DataVisualizationInsight : DTDFVocab:Insight [
    base:desc "Operator can view live sensor traces, derived torque, velocity, and acceleration"
]

instance DataTraceabilityInsight : DTDFVocab:Insight [
    base:desc "Each data point is linked to its source sensor for full traceability"
]

instance FrictionParameterUpdateAction : DTDFVocab:Action [
    base:desc "Automatic update of the robot's control algorithm with new friction parameters"
    DTDFVocab:IsAutomatic true
]

instance DataIngestionInsight : DTDFVocab:Insight [
    base:desc "Successful ingestion of MQTT sensor streams into the digital twin"
]

// -----------------------------------------------------------------------------
// C10: Engineering & Simulation Models
// -----------------------------------------------------------------------------
instance MotorSysMLModel : DTDFVocab:Model [
    base:desc "SysML block definition & internal block diagram of the permanent‑magnet synchronous motor"
    DTDFVocab:inputTo MatlabSimulinkProcessingEnabler
]

instance GearboxSysMLModel : DTDFVocab:Model [
    base:desc "SysML representation of the gear transmission and cycloidal gearbox"
    DTDFVocab:inputTo MatlabSimulinkProcessingEnabler
]

instance FrictionSysMLModel : DTDFVocab:Model [
    base:desc "SysML model describing Coulomb‑Viscous, Stribeck, Dahl, and LuGre friction concepts"
    DTDFVocab:inputTo FrictionSimulationEnabler
]

instance MatlabSimulinkMotorModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink executable model of the motor dynamics"
    DTDFVocab:inputTo FrictionSimulationEnabler
]

instance MatlabSimulinkGearboxModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink executable model of the gear transmission"
    DTDFVocab:inputTo FrictionSimulationEnabler
]

instance MatlabSimulinkFrictionModel : DTDFVocab:Model [
    base:desc "MATLAB/Simulink executable friction model (Coulomb‑Viscous, Stribeck, Dahl, LuGre)"
    DTDFVocab:inputTo FrictionSimulationEnabler
]

// -----------------------------------------------------------------------------
// Digital Twin Component
// -----------------------------------------------------------------------------
instance FrictionShadow : DTDFVocab:Component [
    base:desc "Digital shadow instance representing the first axis of the MABI MAX 100 robot"
    base:isContainedIn DigitalTwinEnvironment
]

// -----------------------------------------------------------------------------
// Environment containing all components
// -----------------------------------------------------------------------------
instance DigitalTwinEnvironment : DTDFVocab:Environment [
    base:desc "Environment containing all digital shadow components for the first axis"
    base:contains MotorSysMLModel, GearboxSysMLModel, FrictionSysMLModel,
                  MatlabSimulinkMotorModel, MatlabSimulinkGearboxModel, MatlabSimulinkFrictionModel,
                  MQTTPeerBroker, AssetAdministrationShellEnabler, DashboardVisualizationEnabler,
                  FrictionIdentificationService, DataVisualizationService, DataTraceabilityService,
                  FrictionParameterUpdateService,
                  FrictionShadow
]

