    base:desc "Sensor data are transmitted from the robot to the digital shadow via the MQTT protocol; the digital shadow consumes these MQTT messages to populate data traces."
]

instance standardization : DTDFVocab:Standardization [
    base:desc "The implementation employs the Asset Administration Shell (AAS) standard for asset representation and SysML, an ISO/OMG standard for system modeling."
]
